{
  "narrative": "玩家细致准备行囊，检查火把、水囊和干粮，又用炭笔在树皮上画了几个简易路标。老者在一旁默默看着，眼神中似乎有话，却终究没再多言。夜色渐深，山风带着寒意吹来，远处传来几声不知名的鸟鸣。",
  "world_action_candidates": [
    "整理行装，跟随老者走岔路",
    "趁夜色独自探路老山路",
    "再向老者追问关于老山路的传闻"
  ],
  "rumors": [
    "青茅山深处有古修士遗迹，但无人敢深入",
    "南疆边境最近有怪异雾气，吞噬了几支商队"
  ],
  "pressure": [
    "夜色已深，山间气温骤降，体力消耗加快",
    "老者始终不愿透露岔路的具体险情，可能有所隐瞒"
  ],
  "safety_notes": [
    "请保持警惕，准备好火把和武器",
    "路标已做好，但切勿留下明显痕迹引来追踪"
  ]
}

{
  "narrative": "夜色中，一阵风声带来远处篝火堆的谈话片段：有商队数日前在山道岔口遭遇怪雾，失踪了三人，至今未归。老者听到后眉头紧锁，低声念叨了一句'老山路不干净'，随即闭口不语。",
  "world_action_candidates": [
    "继续整理装备，等待天明再出发",
    "向老者追问商队失踪的细节",
    "独自前往岔路口探查痕迹"
  ],
  "rumors": [
    "数日前有商队在青茅山岔口遭遇怪雾，三人失踪"
  ],
  "pressure": [
    "夜色已深，气温持续下降",
    "老者似乎知晓山道隐患却不愿明说",
    "商队失踪传闻可能暗示前路危险"
  ],
  "safety_notes": [
    "当前仍在青茅山安全营地范围内",
    "建议不要独自夜间进入陌生岔路"
  ]
}

{
  "narrative": "一名低阶散修站在不远处山脊上，目光紧锁你的方向。他腰间的葫芦泛着微光，显然已察觉你的存在。青茅山外缘雾气翻涌，地面微微颤动，南疆投影的边界愈发模糊。你感到一丝被监视的压力，此人来意不明，或许掌握着此地的隐秘路径。",
  "world_action_candidates": [
    "沿扭曲小径继续疾行，甩开监视",
    "试探性向散修喊话，询问前方情报"
  ],
  "rumors": [
    "有散修声称青茅山深处藏有古修洞府，但路径被阵法扭曲",
    "南疆外缘投影不稳，可能与宝黄天异动有关"
  ],
  "pressure": [
    "散修监视带来的潜在敌意",
    "雾气压缩感知范围至十步之内",
    "脚下地面出现细密裂纹，随时可能塌陷"
  ],
  "safety_notes": [
    "避免长时间停留，防止被散修锁定位置",
    "注意雾气中可能潜伏的凶兽，保持警惕"
  ]
}

{
  "narrative": "你提出寻找市场售卖材料，但此地仅为南疆外缘投影，并无正式市集。山脊上的散修冷笑一声，指了个模糊方向，传言有临时交易点但真假难辨。雾气更浓，地面震颤加剧，隐约可闻远处低吼。",
  "world_action_candidates": [
